import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { ThemeProvider, createTheme } from '@mui/material';
import CssBaseline from '@mui/material/CssBaseline';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import ProductDetails from './pages/ProductDetails';
import AddProduct from './pages/AddProduct';
import EditProduct from './pages/EditProduct';
import MyProducts from './pages/MyProducts';
import About from './pages/About';
import Contact from './pages/Contact';
import Terms from './pages/Terms';
import AdminDashboard from './pages/AdminDashboard';
import Notifications from './pages/Notifications';
import { AuthProvider } from './context/AuthContext';

const theme = createTheme({
  direction: 'rtl',
  palette: {
    primary: { main: '#1a5276' },
    secondary: { main: '#2980b9' },
    background: { default: '#f5f6fa' },
  },
  typography: {
    fontFamily: '"Cairo", "Roboto", "Helvetica", "Arial", sans-serif',
  }
});

// ✅ إضافة أنماط CSS للتأثيرات
const glowStyles = `
  @keyframes glow {
    0% { box-shadow: 0 0 5px rgba(26, 82, 118, 0.5); }
    50% { box-shadow: 0 0 20px rgba(26, 82, 118, 0.8), 0 0 40px rgba(41, 128, 185, 0.4); }
    100% { box-shadow: 0 0 5px rgba(26, 82, 118, 0.5); }
  }

  @keyframes float {
    0% { transform: translateY(0px); }
    50% { transform: translateY(-10px); }
    100% { transform: translateY(0px); }
  }

  @keyframes pulse {
    0% { transform: scale(1); }
    50% { transform: scale(1.05); }
    100% { transform: scale(1); }
  }

  @keyframes shimmer {
    0% { background-position: -200% 0; }
    100% { background-position: 200% 0; }
  }

  .glow-effect {
    animation: glow 3s ease-in-out infinite;
  }

  .float-effect {
    animation: float 3s ease-in-out infinite;
  }

  .pulse-effect {
    animation: pulse 2s ease-in-out infinite;
  }

  .shimmer-effect {
    background: linear-gradient(90deg, transparent, rgba(255,255,255,0.4), transparent);
    background-size: 200% 100%;
    animation: shimmer 2s infinite;
  }

  .card-glow {
    transition: all 0.3s ease;
  }

  .card-glow:hover {
    box-shadow: 0 0 30px rgba(26, 82, 118, 0.6), 0 0 60px rgba(41, 128, 185, 0.3);
    transform: translateY(-5px);
  }

  .btn-glow {
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
  }

  .btn-glow:hover {
    box-shadow: 0 0 20px rgba(26, 82, 118, 0.8);
    transform: scale(1.05);
  }

  .btn-glow::after {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: linear-gradient(45deg, transparent, rgba(255,255,255,0.3), transparent);
    transform: rotate(45deg);
    transition: all 0.5s;
    opacity: 0;
  }

  .btn-glow:hover::after {
    opacity: 1;
    transform: rotate(45deg) translate(50%, 50%);
  }

  .logo-glow {
    animation: glow 2s ease-in-out infinite;
    border-radius: 50%;
  }

  .title-glow {
    text-shadow: 0 0 10px rgba(26, 82, 118, 0.5), 0 0 20px rgba(41, 128, 185, 0.3);
  }
`;

function App() {
  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      {/* ✅ إضافة الأنماط */}
      <style>{glowStyles}</style>
      <AuthProvider>
        <Router>
          <Navbar />
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/product/:id" element={<ProductDetails />} />
            <Route path="/add-product" element={<AddProduct />} />
            <Route path="/edit-product/:id" element={<EditProduct />} />
            <Route path="/my-products" element={<MyProducts />} />
            <Route path="/about" element={<About />} />
            <Route path="/contact" element={<Contact />} />
            <Route path="/terms" element={<Terms />} />
            <Route path="/admin" element={<AdminDashboard />} />
            <Route path="/notifications" element={<Notifications />} />
          </Routes>
        </Router>
      </AuthProvider>
    </ThemeProvider>
  );
}

export default App;
